from dataclasses import dataclass

@dataclass
class KeywordRule:
    rule_id: str
    category: str
    label: SensitivityLevel
    terms: list[str]
    case_sensitive: bool = False

    def _pattern(self) -> re.Pattern:
        escaped = [re.escape(t) for t in self.terms]
        flags = 0 if self.case_sensitive else re.IGNORECASE
        return re.compile(r"\b(?:" + "|".join(escaped) + r")\b", flags)

    def match(self, text: str) -> list[str]:
        return self._pattern().findall(text)


KEYWORD_RULES: list[KeywordRule] = [
    KeywordRule("KW-001", "PHI", SensitivityLevel.REGULATED, [
        "diagnosis", "patient", "clinical trial", "prescription",
        "medication", "radiology", "pathology", "HIPAA", "PHI",
    ]),
    KeywordRule("KW-002", "LEGAL", SensitivityLevel.RESTRICTED, [
        "attorney-client", "legal privilege", "work product",
        "pending litigation", "settlement agreement", "injunction",
    ]),
    KeywordRule("KW-003", "FINANCIAL", SensitivityLevel.CONFIDENTIAL, [
        "MNPI", "material non-public", "earnings guidance",
        "acquisition target", "insider", "tender offer",
    ]),
    KeywordRule("KW-004", "IP", SensitivityLevel.CONFIDENTIAL, [
        "trade secret", "proprietary algorithm", "NDA",
        "non-disclosure", "source code", "roadmap",
    ]),
]


def run_pattern_library(text: str) -> StageResult:
    result = StageResult()
    for kw in KEYWORD_RULES:
        hits = kw.match(text)
        if hits:
            result.matched_rules.append(kw.rule_id)
            result.categories.add(kw.category)
            if kw.label > result.label:
                result.label = kw.label
            result.confident = True
    return result

