from dataclasses import dataclass

@dataclass
class ClassifierMetrics:
    label: str
    true_positives: int
    false_positives: int
    false_negatives: int

    @property
    def precision(self) -> float:
        denom = self.true_positives + self.false_positives
        return self.true_positives / denom if denom else 0.0

    @property
    def recall(self) -> float:
        denom = self.true_positives + self.false_negatives
        return self.true_positives / denom if denom else 0.0

    @property
    def f1(self) -> float:
        p, r = self.precision, self.recall
        return 2 * p * r / (p + r) if (p + r) else 0.0

    def passes_gate(self,
                    min_precision: float = 0.95,
                    min_recall: float = 0.90) -> bool:
        return self.precision >= min_precision and self.recall >= min_recall

    def __str__(self) -> str:
        return (f"{self.label:15s}  "
                f"P={self.precision:.3f}  R={self.recall:.3f}  "
                f"F1={self.f1:.3f}  "
                f"{'PASS' if self.passes_gate() else 'FAIL'}")


def evaluate_classifier(predictions: list[tuple[str, str]]) -> list[ClassifierMetrics]:
    """
    predictions: list of (predicted_label, true_label) pairs.
    Returns one ClassifierMetrics per label.
    """
    labels = sorted({label for _, label in predictions})
    metrics = []
    for label in labels:
        tp = sum(1 for pred, true in predictions if pred == label and true == label)
        fp = sum(1 for pred, true in predictions if pred == label and true != label)
        fn = sum(1 for pred, true in predictions if pred != label and true == label)
        metrics.append(ClassifierMetrics(label, tp, fp, fn))
    return metrics

import json
from dataclasses import dataclass
from datetime import date
from pathlib import Path

@dataclass
class ReviewedExample:
    trace_id: str
    text_snippet: str      # first 500 chars; no raw PII in training data
    ml_predicted_label: str
    human_confirmed_label: str
    reviewed_by: str
    reviewed_at: date
    was_correct: bool      # ml_predicted_label == human_confirmed_label

class FeedbackStore:
    """Append-only store for human-reviewed classification examples."""
    MIN_EXAMPLES_TO_RETRAIN = 500
    MAX_STALENESS_DAYS = 90

    def __init__(self, path: Path):
        self.path = path
        self.path.parent.mkdir(parents=True, exist_ok=True)

    def add(self, example: ReviewedExample) -> None:
        import dataclasses
        with self.path.open("a") as f:
            f.write(json.dumps(dataclasses.asdict(example), default=str) + "\n")

    def examples_since(self, since: date) -> list[dict]:
        if not self.path.exists():
            return []
        return [
            json.loads(line)
            for line in self.path.read_text().splitlines()
            if date.fromisoformat(json.loads(line)["reviewed_at"]) >= since
        ]

    def should_retrain(self, last_retrain: date) -> tuple[bool, str]:
        n = len(self.examples_since(last_retrain))
        days = (date.today() - last_retrain).days
        if n >= self.MIN_EXAMPLES_TO_RETRAIN:
            return True, f"{n} new examples"
        if days >= self.MAX_STALENESS_DAYS:
            return True, f"{days} days since last retrain"
        return False, "no trigger"
